import React from 'react';
import { useNavigate } from 'react-router-dom';
import he from '../i18n/he.json';

export default function OrderSuccess() {
  const navigate = useNavigate();
  return (
    <div className="max-w-md mx-auto mt-10 p-6 bg-white rounded-lg shadow-lg text-center">
      <h2 className="text-2xl text-tomato mb-4">{he.order_success}</h2>
      <div className="mb-2">{he.order_summary}</div>
      <button
        className="mt-4 bg-crust text-tomato px-4 py-2 rounded-lg font-bold hover:bg-orange-300 transition"
        onClick={() => navigate('/')}
      >
        {he.menu_title}
      </button>
    </div>
  );
}
